+        return Ok(DispatchOutcome {
+            payload: json!({
+                "status": "error",
+                "command": "pipe",
+                "error": {
+                    "type": "missing-mapping",
+                    "message": "No mapping provided. Use --map or --map-file.",
+                },
+                "next_actions": [
+                    format!("fwc pipe {} {} --map 'field_a -> field_b'", args.source, args.target),
+                ],
+            }),
+            exit_code: CliExitCode::UnknownCommand,
